import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import StatsSection from '../components/StatsSection';
import NewsSection from '../components/NewsSection';
import '../styles/CoursesPage.css';

const CoursesPage = () => {
    const { t } = useTranslation();
    const [isVisible, setIsVisible] = useState(false);
    const [selectedCourse, setSelectedCourse] = useState(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [activeFilter, setActiveFilter] = useState('all');
    const sectionRef = useRef(null);

    // Enhanced course data with more courses
    const courses = [
        {
            id: 1,
            title: "Full Stack Web Development",
            category: "web-development",
            level: "Beginner to Advanced",
            duration: "12 weeks",
            price: "¥35,000",
            rating: 4.9,
            students: 1250,
            image: require('../assets/images/png5.jpg'),
            instructor: "John Smith",
            description: "Master modern web development with React, Node.js, and MongoDB",
            fullDescription: "This comprehensive course covers everything from HTML/CSS basics to advanced React patterns, backend development with Node.js and Express, database design with MongoDB, and deployment strategies. You'll build 5 real-world projects including an e-commerce platform.",
            skills: ["React", "Node.js", "MongoDB", "Express", "JavaScript", "HTML/CSS"],
            curriculum: [
                "Frontend Fundamentals (HTML, CSS, JavaScript)",
                "React Development & State Management",
                "Backend Development with Node.js",
                "Database Design & MongoDB",
                "API Development & Integration",
                "Deployment & DevOps"
            ],
            prerequisites: ["Basic computer skills", "Problem-solving mindset"],
            certificate: true,
            support: "24/7 Community Support"
        },
        {
            id: 2,
            title: "Data Science & Analytics",
            category: "data-science",
            level: "Intermediate",
            duration: "16 weeks",
            price: "¥48,000",
            rating: 4.8,
            students: 980,
            image: require('../assets/images/png5.jpg'),
            instructor: "Dr. Sarah Johnson",
            description: "Learn Python, machine learning, and data visualization techniques",
            fullDescription: "Dive deep into data science with Python, statistical analysis, machine learning algorithms, and data visualization. Work with real datasets and build predictive models that solve business problems.",
            skills: ["Python", "Pandas", "NumPy", "Scikit-learn", "Matplotlib", "Seaborn"],
            curriculum: [
                "Python for Data Science",
                "Statistical Analysis & Probability",
                "Data Cleaning & Preprocessing",
                "Machine Learning Algorithms",
                "Data Visualization",
                "Capstone Project"
            ],
            prerequisites: ["Basic programming knowledge", "Mathematics background"],
            certificate: true,
            support: "Mentor-guided learning"
        },
        {
            id: 3,
            title: "Cybersecurity Fundamentals",
            category: "cybersecurity",
            level: "Beginner",
            duration: "10 weeks",
            price: "¥30,000",
            rating: 4.7,
            students: 750,
            image: require('../assets/images/png5.jpg'),
            instructor: "Michael Chen",
            description: "Protect digital assets and learn ethical hacking techniques",
            fullDescription: "Master cybersecurity fundamentals including network security, ethical hacking, risk assessment, and security frameworks. Hands-on labs with real-world scenarios.",
            skills: ["Network Security", "Ethical Hacking", "Risk Assessment", "Security Frameworks"],
            curriculum: [
                "Introduction to Cybersecurity",
                "Network Security Fundamentals",
                "Ethical Hacking & Penetration Testing",
                "Risk Management",
                "Security Compliance",
                "Incident Response"
            ],
            prerequisites: ["Basic networking knowledge"],
            certificate: true,
            support: "Industry expert mentorship"
        },
        {
            id: 4,
            title: "Cloud Computing with AWS",
            category: "cloud-computing",
            level: "Intermediate",
            duration: "14 weeks",
            price: "¥42,000",
            rating: 4.8,
            students: 890,
            image: require('../assets/images/png5.jpg'),
            instructor: "Alex Rodriguez",
            description: "Master AWS cloud services and modern cloud architecture",
            fullDescription: "Learn to design, deploy, and manage scalable applications on AWS. Cover EC2, S3, Lambda, RDS, and more. Prepare for AWS certification while building real-world projects.",
            skills: ["AWS", "EC2", "S3", "Lambda", "CloudFormation", "DevOps"],
            curriculum: [
                "AWS Fundamentals & Setup",
                "Compute Services (EC2, Lambda)",
                "Storage Solutions (S3, EBS)",
                "Database Services (RDS, DynamoDB)",
                "Networking & Security",
                "Deployment & Monitoring"
            ],
            prerequisites: ["Basic programming", "Understanding of web applications"],
            certificate: true,
            support: "AWS certified instructors"
        },
        {
            id: 5,
            title: "AI & Machine Learning",
            category: "ai-ml",
            level: "Advanced",
            duration: "20 weeks",
            price: "¥65,000",
            rating: 4.9,
            students: 650,
            image: require('../assets/images/png5.jpg'),
            instructor: "Dr. Emily Watson",
            description: "Deep dive into artificial intelligence and machine learning algorithms",
            fullDescription: "Comprehensive AI/ML course covering neural networks, deep learning, computer vision, and natural language processing. Build real AI applications and understand the latest research.",
            skills: ["TensorFlow", "PyTorch", "Computer Vision", "NLP", "Deep Learning", "Neural Networks"],
            curriculum: [
                "Machine Learning Fundamentals",
                "Neural Networks & Deep Learning",
                "Computer Vision with CNNs",
                "Natural Language Processing",
                "Reinforcement Learning",
                "AI Ethics & Deployment"
            ],
            prerequisites: ["Strong programming skills", "Advanced mathematics", "Statistics background"],
            certificate: true,
            support: "Research-level mentorship"
        },
        {
            id: 6,
            title: "Mobile App Development",
            category: "mobile-development",
            level: "Intermediate",
            duration: "12 weeks",
            price: "¥38,000",
            rating: 4.6,
            students: 920,
            image: require('../assets/images/png5.jpg'),
            instructor: "James Park",
            description: "Build native iOS and Android apps with React Native",
            fullDescription: "Learn to develop cross-platform mobile applications using React Native. Cover navigation, state management, API integration, and deployment to app stores.",
            skills: ["React Native", "JavaScript", "Mobile UI/UX", "API Integration", "App Store Deployment"],
            curriculum: [
                "React Native Fundamentals",
                "Navigation & Routing",
                "State Management",
                "Native Modules & APIs",
                "Testing & Debugging",
                "App Store Deployment"
            ],
            prerequisites: ["JavaScript knowledge", "React experience preferred"],
            certificate: true,
            support: "Mobile development experts"
        },
        {
            id: 7,
            title: "UI/UX Design Masterclass",
            category: "design",
            level: "Beginner to Intermediate",
            duration: "8 weeks",
            price: "¥25,000",
            rating: 4.7,
            students: 1100,
            image: require('../assets/images/png5.jpg'),
            instructor: "Sofia Martinez",
            description: "Master user interface and user experience design principles",
            fullDescription: "Learn design thinking, user research, wireframing, prototyping, and visual design. Use industry tools like Figma and Adobe XD to create stunning user experiences.",
            skills: ["Figma", "Adobe XD", "Design Thinking", "Prototyping", "User Research", "Visual Design"],
            curriculum: [
                "Design Thinking & User Research",
                "Wireframing & Information Architecture",
                "Visual Design Principles",
                "Prototyping & Interaction Design",
                "Usability Testing",
                "Design Systems & Handoff"
            ],
            prerequisites: ["Creative mindset", "Basic computer skills"],
            certificate: true,
            support: "Industry designers network"
        },
        {
            id: 8,
            title: "DevOps Engineering",
            category: "devops",
            level: "Intermediate to Advanced",
            duration: "16 weeks",
            price: "¥52,000",
            rating: 4.8,
            students: 480,
            image: require('../assets/images/png5.jpg'),
            instructor: "David Kumar",
            description: "Master CI/CD, containerization, and infrastructure automation",
            fullDescription: "Learn modern DevOps practices including Docker, Kubernetes, Jenkins, Terraform, and monitoring. Build automated deployment pipelines and manage cloud infrastructure.",
            skills: ["Docker", "Kubernetes", "Jenkins", "Terraform", "AWS", "Monitoring"],
            curriculum: [
                "DevOps Fundamentals & Culture",
                "Containerization with Docker",
                "Orchestration with Kubernetes",
                "CI/CD Pipelines",
                "Infrastructure as Code",
                "Monitoring & Logging"
            ],
            prerequisites: ["Linux basics", "Programming experience", "Cloud knowledge"],
            certificate: true,
            support: "DevOps practitioners community"
        },
        {
            id: 9,
            title: "Blockchain Development",
            category: "blockchain",
            level: "Advanced",
            duration: "18 weeks",
            price: "¥58,000",
            rating: 4.5,
            students: 320,
            image: require('../assets/images/png5.jpg'),
            instructor: "Robert Zhang",
            description: "Build decentralized applications and smart contracts",
            fullDescription: "Learn blockchain technology, smart contract development with Solidity, DApp creation, and cryptocurrency fundamentals. Work with Ethereum, Web3, and modern blockchain tools.",
            skills: ["Solidity", "Ethereum", "Web3.js", "Smart Contracts", "DApps", "Cryptocurrency"],
            curriculum: [
                "Blockchain Fundamentals",
                "Ethereum & Smart Contracts",
                "Solidity Programming",
                "DApp Development",
                "Web3 Integration",
                "Security & Best Practices"
            ],
            prerequisites: ["Strong programming background", "JavaScript experience"],
            certificate: true,
            support: "Blockchain experts network"
        }
    ];

    const filteredCourses = activeFilter === 'all' 
        ? courses 
        : courses.filter(course => course.category === activeFilter);

    useEffect(() => {
        setIsVisible(true);

        const createCubes = () => {
            const world = document.querySelector('.world');
            if (!world) return;

            for (let i = 0; i < 15; i++) {
                const cube = document.createElement('div');
                cube.className = 'cube';

                const x = (Math.random() - 0.5) * 1000;
                const y = (Math.random() - 0.5) * 1000;
                const z = (Math.random() - 0.5) * 1000;
                const size = Math.random() * 50 + 20;

                cube.style.width = `${size}px`;
                cube.style.height = `${size}px`;
                cube.style.transform = `translate3d(${x}px, ${y}px, ${z}px)`;

                ['front', 'back', 'right', 'left', 'top', 'bottom'].forEach(face => {
                    const el = document.createElement('div');
                    el.className = `cube-face ${face}`;
                    cube.appendChild(el);
                });

                world.appendChild(cube);
            }
        };

        createCubes();

        return () => {
            const world = document.querySelector('.world');
            if (world) {
                while (world.firstChild) {
                    world.removeChild(world.firstChild);
                }
            }
        };
    }, []);

    const openModal = (course) => {
        setSelectedCourse(course);
        setIsModalOpen(true);
        // Prevent body scroll when modal is open
